class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLen = 0;
        int zeros = 0;
        int ones = 0;

        for (int i = 0; i < s.length();) {
            while (i < s.length() && s.charAt(i) == '0') {
                zeros++;
                i++;
            }
            while (i < s.length() && s.charAt(i) == '1') {
                ones++;
                i++;
            }
            maxLen = Math.max(maxLen, Math.min(zeros, ones) * 2);
        }

        return maxLen;
    }
}
```
